#!/bin/bash # CORES verde="\e[32m" vermelho="\e[31m" azul="\e[34m" amarelo="\e[33m" reset="\e[0m" # VERIFICA ARGUMENTO if [ "$1" == "" ] then clear echo -e "${azul}" echo "==========================================" echo " PARSING GABRIEL" echo "==========================================" echo -e "${reset}" echo -e "${amarelo}[!] Modo de uso:${reset} $0 URL" echo -e "${amarelo}[!] Exemplo:${reset} ./parsing.sh https://globo.com" echo "" else clear echo -e "${azul}" echo "==========================================" echo " PARSING GABRIEL" echo "==========================================" echo -e "${reset}" echo -e "${verde}[+] Removendo arquivos antigos...${reset}" rm -f index.html lista sleep 1 echo -e "${verde}[+] Baixando conteúdo da URL...${reset}" wget -q $1 # VERIFICA SE O DOWNLOAD FUNCIONOU if [ ! -f index.html ] then echo "" echo -e "${vermelho}[!] ERRO: Não foi possível baixar o site.${reset}" exit fi sleep 1 echo -e "${verde}[+] Extraindo domínios encontrados...${reset}" grep -oP '(?<=href=")[^"]*' index.html | cut -d "/" -f 3 | grep "\." | grep -v "javascript" | sort -u > lista sleep 1 echo "" echo -e "${azul}==========================================${reset}" echo -e "${verde}[+] HOSTS ENCONTRADOS:${reset}" echo -e "${azul}==========================================${reset}" echo "" for url in $(cat lista) do echo -e "${amarelo}[HOST]${reset} $url" host $url | grep "has address" echo "" done echo -e "${azul}==========================================${reset}" echo -e "${verde}[+] Parsing finalizado com sucesso!${reset}" echo -e "${azul}==========================================${reset}" fi
